import{_ as r,o as a,c as t,ag as o}from"./chunks/framework.B45ElpZ1.js";const u=JSON.parse(`{"title":"Browser Setup","description":"Configure Chrome for tradecli's browser-driven workflows.","frontmatter":{"title":"Browser Setup","description":"Configure Chrome for tradecli's browser-driven workflows.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/getting-started/browser-setup"}]]},"headers":[],"relativePath":"getting-started/browser-setup.md","filePath":"getting-started/browser-setup.md"}`),i={name:"getting-started/browser-setup.md"};function s(l,e,n,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="browser-setup" tabindex="-1">Browser Setup <a class="header-anchor" href="#browser-setup" aria-label="Permalink to &quot;Browser Setup&quot;">​</a></h1><p>Some tradecli workflows need a real browser because the source of truth is a web app: TradingView, Screener.in, broker screens, or login surfaces. Browser setup is handled by the same local setup path as the rest of the product.</p><h2 id="why-a-dedicated-browser" tabindex="-1">Why a dedicated browser <a class="header-anchor" href="#why-a-dedicated-browser" aria-label="Permalink to &quot;Why a dedicated browser&quot;">​</a></h2><p>Browser-driven workflows are used when an API is unavailable, incomplete, or when the workflow needs to read the same screen a trader would inspect manually.</p><p>The browser path is designed to keep the operator in control:</p><ul><li>tradecli uses a local browser profile.</li><li>Broker logins happen on the machine running tradecli.</li><li>Agents can read context and prepare work, but broker actions still require explicit user approval.</li></ul><h2 id="chrome-chromium-requirements" tabindex="-1">Chrome/Chromium requirements <a class="header-anchor" href="#chrome-chromium-requirements" aria-label="Permalink to &quot;Chrome/Chromium requirements&quot;">​</a></h2><p>Install Chrome or a compatible Chromium browser before running setup. Then run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>Setup checks the browser path and creates the local browser profile when needed. You can re-check the environment with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="the-tradecli-browser-profile" tabindex="-1">The tradecli browser profile <a class="header-anchor" href="#the-tradecli-browser-profile" aria-label="Permalink to &quot;The tradecli browser profile&quot;">​</a></h2><p>tradecli keeps its browser automation state separate from your everyday browser profile. That reduces accidental session crossover and makes doctor repairs safer.</p><p>Use <code>tradecli doctor --fix</code> if the browser profile is missing, stale, or no longer launches cleanly.</p><h2 id="first-run-flow" tabindex="-1">First-run flow <a class="header-anchor" href="#first-run-flow" aria-label="Permalink to &quot;First-run flow&quot;">​</a></h2><ol><li>Install tradecli.</li><li>Run <code>tradecli setup</code>.</li><li>Launch <code>tradecli</code>.</li><li>Choose a browser-aware workflow, such as TradingView, Screener.in, or a broker-aware flow.</li><li>Complete any first-use login prompt in the local browser window.</li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>Run <code>tradecli doctor</code>.</li><li>Run <code>tradecli doctor --fix</code> for safe repairs.</li><li>Confirm Chrome launches normally outside tradecli.</li><li>Re-run <code>tradecli setup</code> after changing model credentials, broker state, or browser installation.</li><li>If you&#39;re still stuck, email <a href="mailto:contact@tradecli.in" target="_blank" rel="noreferrer">contact@tradecli.in</a>.</li></ul>',18)])])}const b=r(i,[["render",s]]);export{u as __pageData,b as default};
